#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

static bool controller_sensor_is_fresh(bool has_valid_sample, uint32_t last_sample_ms, uint32_t now_ms)
{
    if (!has_valid_sample) {
        return false;
    }

    return (uint32_t) (now_ms - last_sample_ms) <= CONTROLLER_SENSOR_TIMEOUT_MS;
}

static void controller_apply_policy(controller_t *controller, bool has_previous_temperature)
{
    const bool temperature_fresh = controller_sensor_is_fresh(
        controller->has_valid_temperature,
        controller->last_temperature_ms,
        controller->last_level_ms > controller->last_temperature_ms ? controller->last_level_ms : controller->last_temperature_ms
    );
    const bool level_fresh = controller_sensor_is_fresh(
        controller->has_valid_level,
        controller->last_level_ms,
        controller->last_level_ms > controller->last_temperature_ms ? controller->last_level_ms : controller->last_temperature_ms
    );
    const int level = controller->last_level;
    const int temperature_c = controller->last_temperature_c;
    bool hold_heater_on;
    bool temperature_rising = false;

    if (!temperature_fresh || !level_fresh) {
        controller_set_safe_idle(controller);
        return;
    }

    if (has_previous_temperature) {
        temperature_rising = temperature_c > controller->previous_temperature_c;
    }

    hold_heater_on = controller->heater_on;
    if (level < CONTROLLER_MIN_HEATING_LEVEL) {
        hold_heater_on = false;
    }
    if (temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
        hold_heater_on = false;
    }

    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_HOLDING;

    if (temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
        controller->inlet_open = false;
        controller->heater_on = false;
        return;
    }

    if (level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
        controller->inlet_open = true;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_FILLING;
        return;
    }

    if (level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
        controller->inlet_open = false;
        controller->heater_on = false;
        return;
    }

    if (temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
        controller->inlet_open = false;
        controller->heater_on = true;
        controller->state = CONTROLLER_STATE_HEATING;
        return;
    }

    if (temperature_c < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
        controller->inlet_open = false;
        controller->heater_on = hold_heater_on;
        controller->state = controller->heater_on ? CONTROLLER_STATE_HEATING : CONTROLLER_STATE_HOLDING;
        return;
    }

    if (temperature_rising) {
